  is_affiliate, review_slug, external_url, is_top_pick, best_for, display_order,
  source_url, data_verified_at, active
) VALUES
(
  NULL,
  'augusta', 'us', 'gold-investing', 'platforms', 'Augusta Precious Metals', 'Best overall / cleanest complaint record (requires $50,000 minimum)',
  9.0, 4.8, 350, 0, 0, 50000, 0,
  '{"segment":"gold_ira_specialist","starting_price_headline":"Phone-quoted premiums; ~$180-230/yr IRA fees","starting_price_note":"No published price list — 1:1 phone consultation required for any product quote. Standard (non-promo) IRA fees: $50 setup + $30 wire one-time, then ~$80/yr custodian (Equity Trust) + ~$100-150/yr storage ≈ $180-230/yr. A recurring \"fees waived up to 10 years\" promo is advertised in Augusta''s own affiliate materials — cited as a vendor claim, not a guaranteed standard rate.","min_investment_note":"$50,000 (IRA and cash purchases) — the highest minimum in this comparison","min_investment_usd":50000,"storage_note":"Custodian: Equity Trust (recommended). Depository: Delaware Depository, multiple locations, segregated or commingled storage available.","core_features_note":"Lifetime customer-support commitment, 1:1 web conference with a Harvard-trained economist (vendor-described positioning), buyback program (no guaranteed price), 7-day return window for first-time buyers (confirm current terms directly).","target_user_note":"Well-capitalized retirees ($50k+) who want maximum process hand-holding and value a genuinely clean complaint record over the lowest possible entry point.","founded_year":2012,"bbb_rating_note":"A+, 0 complaints in 3 years (BBB) — the cleanest record in this comparison; BCA rated AAA.","analyst_leader":true,"analyst_leader_note":"Investopedia has repeatedly cited Augusta for pricing transparency across multiple years — a vendor-cited recognition, not an independent-consensus \"#1\" ranking (as of mid-2026, Money.com''s own current top pick in this category is a different company).","clean_incident_record":true,"review_score":4.8,"review_count":350,"review_source":"Trustpilot","review_note":"Smallest Trustpilot sample in this comparison (350 reviews) alongside the cleanest BBB record — both facts shown together rather than letting the small sample stand alone.","regulatory_history_note":"No enforcement action, no class action found. Disclosure: Joe Montana has been a paid brand ambassador since 2020 (disclosed by Augusta itself) — standard for this industry''s celebrity-endorsement marketing pattern, not a red flag on its own.","editorial_consensus_note":"Multi-year Investopedia pricing-transparency recognition (vendor-cited); consistently listed among gold IRA companies in mainstream comparison coverage, though not the current top pick in every list."}'::jsonb,
  'official', 'high',
  '[{"type":"gold","label":"Top pick"}]'::jsonb,
  ARRAY['Cleanest complaint record in this comparison (0 BBB complaints/3yr)','Fees waived up to 10 years (promo, vendor claim)','Investopedia pricing-transparency recognition (multi-year)']::text[],
  ARRAY['The cleanest complaint record in this comparison — 0 BBB complaints in 3 years, BCA-rated AAA','Multi-year Investopedia recognition for pricing transparency (a vendor-cited recognition, not an independent-consensus #1)','A 1:1 phone consultation and lifetime customer-support commitment for buyers who want maximum hand-holding']::text[],
  ARRAY['The highest minimum in this comparison at $50,000 (IRA and cash purchases both)','No published price list — any real premium requires a phone call','Joe Montana is a paid brand ambassador (disclosed), a common celebrity-endorsement pattern in this industry']::text[],
  '{"cost":7.4,"features":8.8,"ux":8.6,"support":9.2}'::jsonb,
  'The cleanest complaint record in this comparison, but it requires the highest minimum',
  'Augusta Precious Metals has the cleanest complaint record of any candidate in this comparison — zero BBB complaints in three years, plus a AAA Business Consumer Alliance rating — and has been repeatedly cited by Investopedia for pricing transparency (a vendor-cited recognition, not an independent #1 ranking). The trade-off is a $50,000 minimum for both IRA and cash purchases, the highest in this comparison, and no published price list — getting a real quote requires a 1:1 phone consultation. Standard IRA fees run roughly $180-230/year (setup/wire one-time, then custodian + storage), with a "fees waived up to 10 years" promotion advertised as a vendor claim rather than a guaranteed rate.',
  false, NULL, 'https://www.augustapreciousmetals.com/', true, 'Best overall / cleanest complaint record', 1,
  'https://www.augustapreciousmetals.com/', DATE '2026-07-05', true
),
(
  NULL,
  'goldco', 'us', 'gold-investing', 'platforms', 'Goldco', 'Best known brand for IRA rollovers',
  8.2, 4.4, 1786, 0, 0, 3500, 0,
  '{"segment":"gold_ira_specialist","starting_price_headline":"Phone-quoted premiums; ~$200-250/yr ongoing (higher year 1)","starting_price_note":"No published price list. IRA fees: $50 setup + $30 wire (one-time, first year only), then $100/yr maintenance + $100-150/yr storage ≈ $200-250/yr ongoing — first-year total (including the one-time setup/wire) runs roughly $280-330 (editorial consensus). A \"free silver\" promotion (5% back on purchases $50k+, 10% on $100k+) is advertised — economically, this is priced into the metal markup rather than a genuine discount, not free money.","min_investment_note":"$25,000 IRA rollover / $3,500 cash purchase","min_investment_usd":3500,"storage_note":"Custodian: Equity Trust (preferred). Depositories: Delaware Depository and Brink''s Global Services (Lloyd''s-insured).","core_features_note":"401(k)/IRA rollover guidance, buyback program (\"highest price buyback\" is a vendor claim), education library, IRS 408(m)-compliant metal selection.","target_user_note":"Rollover customers with $25k+ who want an established, heavily-marketed brand and are comfortable with phone-based sales.","founded_year":2006,"bbb_rating_note":"A+, 59 complaints in 3 years (all answered) — a meaningful volume that scales with Goldco''s larger customer base, though lower than American Hartford Gold''s complaint count in this comparison.","analyst_leader":false,"clean_incident_record":false,"review_score":4.4,"review_count":1786,"review_source":"Trustpilot","review_note":"Reviewed 4.4/5 from 1,786 Trustpilot reviews; ConsumerAffairs shows a higher 4.8, illustrating how much these scores can vary by platform.","regulatory_history_note":"No enforcement action, no product-quality finding. Disclosure: a $2,000,000 TCPA class-action settlement was finally approved March 26, 2026 (Summerton v. Goldco Direct LLC, W.D. Wis. 3:23-cv-238) over marketing text messages sent to Do-Not-Call-registered numbers after opt-out. This is a marketing-practice violation, not a finding about metal pricing or IRA handling — but it fits this industry''s broader pattern of aggressive sales outreach and belongs on the card.","editorial_consensus_note":"Widely marketed brand with strong paid-PR presence (Love Gold, Pierce Points — not independently verifiable rankings); genuine editorial-list membership exists but without a distinct \"#1\" claim that holds up to verification."}'::jsonb,
  'official', 'high',
  '[]'::jsonb,
  ARRAY['Established, heavily-marketed IRA rollover brand','$3,500 cash purchase floor (lower than Augusta/AHG)','Buyback program + IRS 408(m)-compliant selection']::text[],
  ARRAY['One of the most widely recognized brands for 401(k)/IRA gold rollovers, with dedicated rollover guidance','A comparatively low $3,500 cash-purchase floor versus a $25,000 IRA rollover minimum','Reviewed 4.4/5 from 1,786 Trustpilot reviews, with a higher 4.8 on ConsumerAffairs']::text[],
  ARRAY['No published price list — real premiums require a phone call, and first-year IRA costs run roughly $280-330 all-in','A $2,000,000 TCPA class-action settlement was finalized in March 2026 over unsolicited marketing texts','59 BBB complaints in 3 years, a meaningful volume even though all were answered']::text[],
  '{"cost":7.2,"features":8.2,"ux":8.0,"support":8.0}'::jsonb,
  'The best-known brand for IRA rollovers, with a real marketing-practice disclosure',
  'Goldco is one of the most recognized brands for 401(k)/IRA gold rollovers, with a comparatively low $3,500 cash-purchase floor (versus a $25,000 IRA rollover minimum) and a 4.4/5 score from 1,786 Trustpilot reviews. Like its IRA-specialist peers, it publishes no price list — standard ongoing IRA fees run roughly $200-250/year, with a $280-330 first-year total once the one-time setup and wire fees are included. A $2,000,000 TCPA class-action settlement over unsolicited marketing texts was finally approved in March 2026 — a marketing-practice violation, not a finding about metal pricing or IRA handling, but worth knowing given the industry''s broader pattern of aggressive outreach.',
  false, 'goldco-review', 'https://goldco.com/', false, 'Best known brand for IRA rollovers', 5,
  'https://goldco.com/', DATE '2026-07-05', true
),
(
  NULL,
  'american-hartford-gold', 'us', 'gold-investing', 'platforms', 'American Hartford Gold', 'Mid-range IRA minimum, most-discussed complaint pattern (read the disclosure first)',
  7.6, 4.7, 1693, 0, 0, 5000, 0,
  '{"segment":"gold_ira_specialist","starting_price_headline":"Phone-quoted premiums; ~$175-280/yr editorial estimate","starting_price_note":"No published fee structure on AHG''s own site (confirmed via live check, 2026-07-05) — AHG states only that \"every custodian has its own fee structure.\" Two editorial estimates exist and don''t fully agree: an older component-based estimate of $175-280/yr (from $75-125/yr custodian + $100/yr storage + $50-100/yr for segregated storage), and a live-checked comparisun.com estimate (2026-07-05) of $180-250/yr all-in. First-year-fee-waiver promotions are commonly advertised (\"100% free IRA rollover\" marketing is a waiver promo, not a permanently free account). Treat any specific dollar breakdown as an editorial estimate, not a confirmed structure — no official source publishes one.","min_investment_note":"$10,000 IRA / $5,000 cash purchase","min_investment_usd":5000,"storage_note":"Custodian: Equity Trust (primary). Storage in \"approved depositories\" (Delaware Depository among them; confirm current full list directly).","core_features_note":"Price-match and satisfaction claims, buyback commitment, choice of physical delivery or IRA placement. Bill O''Reilly is a paid, multi-year exclusive endorser (disclosed).","target_user_note":"First-time gold IRA buyers with $10-50k who want a mid-range entry point among the IRA specialists — but should insist on standard bullion only and get any markup in writing (see regulatory disclosure).","founded_year":2015,"bbb_rating_note":"A+ accredited, 93 complaints in 3 years — the highest complaint volume in this comparison.","analyst_leader":true,"analyst_leader_note":"CNBC Select has named AHG among gold IRA companies with some of the lowest advertised fees in the category (2026).","clean_incident_record":false,"review_score":4.7,"review_count":1693,"review_source":"Trustpilot","review_note":"Also cited: Google 4.8/1,604, ConsumerAffairs 4.8/1,134 — broadly consistent with the Trustpilot figure.","regulatory_history_note":"No enforcement action, no certified class action — but the most documented warning pattern in this comparison. A 2023 MSNBC investigative piece named AHG alongside other gold-IRA sellers over sales tactics targeting older, conservative-leaning consumers via targeted Facebook ads and fear-based scripts. A documented complaint pattern describes sales staff steering customers from standard bullion toward \"specialty\" or \"exclusive\" coins carrying alleged 45-100% markups, with buyback losses reported in some cases. Kiesel Law LLP announced an investigation into potential FTC/CFTC-relevant undisclosed spreads in October 2023 — an investigation, not a filed lawsuit, and no charges have resulted. We disclose this directly rather than omit it: if you work with AHG, insist on standard bullion products and get any markup in writing before purchasing.","editorial_consensus_note":"CNBC Select \"lowest fees\" pick (2026); Inc. 5000 honoree (2024) — a real growth signal, not a product-quality rating."}'::jsonb,
  'official', 'medium',
  '[]'::jsonb,
  ARRAY['CNBC Select "lowest advertised fees" pick (2026)','Choice of physical delivery or IRA placement','Read the markup-complaint disclosure before buying']::text[],
  ARRAY['CNBC Select has named AHG among gold IRA companies with some of the lowest advertised fees in the category','A mid-range $10,000 IRA / $5,000 cash entry point among the five IRA specialists','Strong review base: 4.7/5 from 1,693 Trustpilot reviews, with consistent Google and ConsumerAffairs scores']::text[],
  ARRAY['The most documented warning pattern in this comparison: a 2023 MSNBC piece and a law-firm investigation into markup practices on specialty coins','The highest BBB complaint volume in this comparison at 93 complaints in 3 years','No official fee structure is published — two editorial estimates exist and don''t fully agree ($175-280/yr vs. $180-250/yr)']::text[],
  '{"cost":7.6,"features":8.0,"ux":8.2,"support":7.4}'::jsonb,
  'A mid-range entry point with the most-documented complaint pattern in this comparison',
  'American Hartford Gold offers a mid-range entry point among the five IRA specialists ($10,000 for an IRA, $5,000 for a cash purchase) and has been named by CNBC Select among gold IRA companies with some of the lowest advertised fees in the category. It carries a strong 4.7/5 score from 1,693 Trustpilot reviews. The honest disclosure: AHG has the most documented warning pattern in this comparison — a 2023 MSNBC investigative piece and a law firm investigation into a complaint pattern describing sales staff steering customers toward "specialty" coins with alleged 45-100% markups. No charges have resulted, but if you work with AHG, insist on standard bullion products and get any markup in writing.',
  false, NULL, 'https://www.americanhartfordgold.com/', false, 'Mid-range IRA minimum, most-discussed complaint pattern', 4,
  'https://www.americanhartfordgold.com/', DATE '2026-07-05', true
),
